  1→using System.IO;
  2→using System.Net;
  3→using System.Net.Sockets;
  4→using System.Text;
  5→using TmRobotEx.Scenario;
  6→using TmRobotEx.WorkPlate;
  7→
  8→namespace TmRobotEx.Bridge;
  9→
 10→/// <summary>
 11→/// TCP 5001 브릿지 서버.
 12→/// sd_bridge.py의 C# 포팅.
 13→/// TMscript(TCP) → 이 서버 → Compute Box(XML-RPC)
 14→/// </summary>
 15→public class BridgeServer
 16→{
 17→    private TcpListener? _listener;
 18→    private CancellationTokenSource? _cts;
 19→    private readonly int _port;
 20→    private readonly SemaphoreSlim _cmdLock = new(1, 1);
 21→
 22→    private const double BUSY_POLL_SEC = 0.1;
 23→    private const double BUSY_TIMEOUT_SEC = 30;
 24→
 25→    public ComputeBoxClient CbClient { get; }
 26→    public WorkPlateData? PlateData { get; set; }
 27→
 28→    // 시나리오 연동
 29→    private ScrewScenario? _scenario;
 30→    private int _currentStepIndex;
 31→    private bool _scenarioRunning;
 32→
 33→    public event Action<string>? LogMessage;
 34→
 35→    /// <summary>
 36→    /// 스텝 시작 (stepIndex, operation) — TMflow가 next_step 요청 시
 37→    /// </summary>
 38→    public event Action<int, ScrewOperation>? StepStarted;
 39→
 40→    /// <summary>
 41→    /// 스텝 완료 (stepIndex, operation, success, achievedTorque) — TMflow가 step_result 보고 시
 42→    /// </summary>
 43→    public event Action<int, ScrewOperation, bool, double>? StepCompleted;
 44→
 45→    /// <summary>
 46→    /// 시나리오 전체 완료
 47→    /// </summary>
 48→    public event Action? ScenarioCompleted;
 49→
 50→    public BridgeServer(int port, string cbUrl, int cbTimeout)
 51→    {
 52→        _port = port;
 53→        CbClient = new ComputeBoxClient(cbUrl, cbTimeout);
 54→    }
 55→
 56→    /// <summary>
 57→    /// 시나리오 실행 모드 시작 (TMflow 대기)
 58→    /// </summary>
 59→    public void StartScenario(ScrewScenario scenario)
 60→    {
 61→        _scenario = scenario;
 62→        _currentStepIndex = 0;
 63→        _scenarioRunning = true;
 64→        LogMessage?.Invoke($"시나리오 대기 시작: {scenario.Name} ({scenario.Operations.Count}개 스텝)");
 65→    }
 66→
 67→    /// <summary>
 68→    /// 시나리오 실행 모드 정지
 69→    /// </summary>
 70→    public void StopScenario()
 71→    {
 72→        _scenarioRunning = false;
 73→        _scenario = null;
 74→        LogMessage?.Invoke("시나리오 대기 중지");
 75→    }
 76→
 77→    public bool IsScenarioRunning => _scenarioRunning;
 78→
 79→    public Task StartAsync()
 80→    {
 81→        _cts = new CancellationTokenSource();
 82→        _listener = new TcpListener(IPAddress.Any, _port);
 83→        _listener.Start();
 84→        LogMessage?.Invoke($"브릿지 서버 대기 중 — 0.0.0.0:{_port}");
 85→
 86→        // 수신 루프 (백그라운드)
 87→        _ = Task.Run(() => AcceptLoop(_cts.Token));
 88→        return Task.CompletedTask;
 89→    }
 90→
 91→    public void Stop()
 92→    {
 93→        _cts?.Cancel();
 94→        try { _listener?.Stop(); } catch { }
 95→        _listener = null;
 96→        CbClient.Dispose();
 97→    }
 98→
 99→    private async Task AcceptLoop(CancellationToken token)
100→    {
101→        while (!token.IsCancellationRequested)
102→        {
103→            try
104→            {
105→                var client = await _listener!.AcceptTcpClientAsync(token);
106→                var addr = ((IPEndPoint)client.Client.RemoteEndPoint!).Address;
107→                LogMessage?.Invoke($"{addr} 접속");
108→                _ = Task.Run(() => HandleClient(client, addr.ToString(), token));
109→            }
110→            catch (OperationCanceledException) { break; }
111→            catch (Exception ex)
112→            {
113→                if (!token.IsCancellationRequested)
114→                    LogMessage?.Invoke($"Accept 오류: {ex.Message}");
115→            }
116→        }
117→    }
118→
119→    private async Task HandleClient(TcpClient client, string addr, CancellationToken token)
120→    {
121→        try
122→        {
123→            using var stream = client.GetStream();
124→            using var reader = new StreamReader(stream, Encoding.UTF8);
125→            using var writer = new StreamWriter(stream, Encoding.UTF8) { AutoFlush = true };
126→
127→            while (!token.IsCancellationRequested)
128→            {
129→                var line = await reader.ReadLineAsync(token);
130→                if (line == null) break;
131→
132→                line = line.Trim();
133→                if (string.IsNullOrEmpty(line)) continue;
134→
135→                LogMessage?.Invoke($"{addr} > {line}");
136→                var t0 = DateTime.Now;
137→
138→                string result;
139→                try
140→                {
141→                    result = await DispatchAsync(line);
142→                }
143→                catch (Exception ex)
144→                {
145→                    result = $"ERR:{ex.Message}";
146→                }
147→
148→                var ms = (DateTime.Now - t0).TotalMilliseconds;
149→                LogMessage?.Invoke($"{addr} < {result}  ({ms:F0}ms)");
150→
151→                await writer.WriteLineAsync(result);
152→            }
153→        }
154→        catch (OperationCanceledException) { }
155→        catch (Exception ex)
156→        {
157→            if (!token.IsCancellationRequested)
158→                LogMessage?.Invoke($"{addr} 핸들러 오류: {ex.Message}");
159→        }
160→        finally
161→        {
162→            client.Close();
163→            LogMessage?.Invoke($"{addr} 연결 끊김");
164→        }
165→    }
166→
167→    /// <summary>
168→    /// 명령 디스패처 (SemaphoreSlim으로 직렬화)
169→    /// </summary>
170→    private async Task<string> DispatchAsync(string cmdLine)
171→    {
172→        var parts = cmdLine.Split(' ', StringSplitOptions.RemoveEmptyEntries);
173→        if (parts.Length == 0) return "ERR:빈 명령";
174→
175→        var cmd = parts[0].ToLower();
176→        var args = parts[1..];
177→
178→        await _cmdLock.WaitAsync();
179→        try
180→        {
181→            return cmd switch
182→            {
183→                "config" => await CmdConfig(args),
184→                "pickup" => await CmdPickup(args),
185→                "tighten" => await CmdTighten(args),
186→                "loosen" => await CmdLoosen(args),
187→                "shank" => await CmdShank(args),
188→                "stop" => await CmdStop(),
189→                "status" => await CmdStatus(),
190→                "recover" => await CmdRecover(),
191→                "raw" => await CmdRaw(args),
192→                "next_hole" => CmdNextHole(),
193→                "hole_result" => CmdHoleResult(args),
194→                "get_coord" => CmdGetCoord(args),
195→                "next_step" => CmdNextStep(),
196→                "step_result" => CmdStepResult(args),
197→                _ => $"ERR:unknown '{cmd}'"
198→            };
199→        }
200→        catch (Exception ex)
201→        {
202→            LogMessage?.Invoke($"dispatch 예외: {ex.Message}");
203→            return $"ERR:{ex.Message}";
204→        }
205→        finally
206→        {
207→            _cmdLock.Release();
208→        }
209→    }
210→
211→    #region 기본 명령 (sd_bridge.py 동일)
212→
213→    private async Task<string> CmdConfig(string[] args)
214→    {
215→        double extender = args.Length > 0 && double.TryParse(args[0], out var e) ? e : 0;
216→        await CbClient.ConfigAsync(extender);
217→        return $"OK:config extender={extender}";
218→    }
219→
220→    private async Task<string> CmdPickup(string[] args)
221→    {
222→        if (args.Length < 2) return "ERR:pickup <force_N> <len_mm>";
223→        int force = int.Parse(args[0]);
224→        double length = double.Parse(args[1]);
225→
226→        await CbClient.PickupScrewAsync(force, length);
227→        var done = await WaitUntilDone(waitStart: true);
228→        var error = await CbClient.GetErrorCodeAsync();
229→        if (!done) return $"ERR:pickup timeout,error={error}";
230→        if (error != 0) return $"ERR:pickup error={error}";
231→        await WaitRetract();
232→        return "OK:pickup";
233→    }
234→
235→    private async Task<string> CmdTighten(string[] args)
236→    {
237→        if (args.Length < 3) return "ERR:tighten <force_N> <len_mm> <torque_Nm>";
238→        int force = int.Parse(args[0]);
239→        double length = double.Parse(args[1]);
240→        double torque = double.Parse(args[2]);
241→
242→        await CbClient.TightenAsync(force, length, torque);
243→        var done = await WaitUntilDone(waitStart: true);
244→        var achieved = await CbClient.GetTorqueAsync();
245→        var error = await CbClient.GetErrorCodeAsync();
246→        if (!done) return $"ERR:tighten timeout,torque={achieved:F2},error={error}";
247→        if (error != 0) return $"ERR:tighten error={error},torque={achieved:F2}";
248→        await WaitRetract();
249→        return $"OK:tighten torque={achieved:F2}";
250→    }
251→
252→    private async Task<string> CmdLoosen(string[] args)
253→    {
254→        if (args.Length < 2) return "ERR:loosen <force_N> <len_mm>";
255→        int force = int.Parse(args[0]);
256→        double length = double.Parse(args[1]);
257→
258→        await CbClient.LoosenAsync(force, length);
259→        var done = await WaitUntilDone(waitStart: true);
260→        var error = await CbClient.GetErrorCodeAsync();
261→        if (!done) return $"ERR:loosen timeout,error={error}";
262→        if (error != 0) return $"ERR:loosen error={error}";
263→        await WaitRetract();
264→        return "OK:loosen";
265→    }
266→
267→    private async Task<string> CmdShank(string[] args)
268→    {
269→        if (args.Length < 1) return "ERR:shank <pos> (0=후퇴, 55=전진)";
270→        int pos = int.Parse(args[0]);
271→        await CbClient.MoveShankAsync(pos);
272→        return "OK:shank";
273→    }
274→
275→    private async Task<string> CmdStop()
276→    {
277→        await CbClient.StopAsync();
278→        return "OK:stop";
279→    }
280→
281→    private async Task<string> CmdStatus()
282→    {
283→        var error = await CbClient.GetErrorCodeAsync();
284→        var safety = await CbClient.GetZSafetyActivatedAsync();
285→
286→        if (error != 0 || safety)
287→        {
288→            LogMessage?.Invoke($"에러/안전 감지 (error={error}, safety={safety}), 자동 복구...");
289→            await CbClient.MoveShankAsync(0);
290→            await Task.Delay(3000);
291→            await WaitUntilDone(timeout: 10);
292→        }
293→
294→        var busy = await CbClient.GetBusyAsync();
295→        var torque = await CbClient.GetTorqueAsync();
296→        error = await CbClient.GetErrorCodeAsync();
297→        return $"OK:busy={Convert.ToInt32(busy)},torque={torque:F2},error={error}";
298→    }
299→
300→    private async Task<string> CmdRecover()
301→    {
302→        await CbClient.MoveShankAsync(0);
303→        await Task.Delay(3000);
304→        await WaitUntilDone(timeout: 10);
305→        var error = await CbClient.GetErrorCodeAsync();
306→        var safety = await CbClient.GetZSafetyActivatedAsync();
307→        if (error == 0 && !safety)
308→            return "OK:recover";
309→        return $"ERR:recover error={error},safety={Convert.ToInt32(safety)}";
310→    }
311→
312→    private async Task<string> CmdRaw(string[] args)
313→    {
314→        if (args.Length == 0) return "ERR:raw <method> [args...]";
315→        var method = args[0];
316→        var callArgs = new object[args.Length - 1];
317→        for (int i = 1; i < args.Length; i++)
318→        {
319→            if (int.TryParse(args[i], out var iv)) callArgs[i - 1] = iv;
320→            else if (double.TryParse(args[i], out var dv)) callArgs[i - 1] = dv;
321→            else callArgs[i - 1] = args[i];
322→        }
323→        var result = await CbClient.CallRawAsync(method, callArgs);
324→        return $"OK:{result}";
325→    }
326→
327→    #endregion
328→
329→    #region 확장 명령 (시나리오 연동)
330→
331→    private string CmdNextHole()
332→    {
333→        if (PlateData == null) return "ERR:작업판 없음";
334→        var next = PlateData.GetNextEmpty();
335→        if (next == null) return "ERR:빈 홀 없음";
336→        return $"OK:{next.Value.col},{next.Value.row}";
337→    }
338→
339→    private string CmdHoleResult(string[] args)
340→    {
341→        if (PlateData == null) return "ERR:작업판 없음";
342→        if (args.Length < 4) return "ERR:hole_result <col> <row> <ok|ng> <torque>";
343→        int col = int.Parse(args[0]);
344→        int row = int.Parse(args[1]);
345→        var status = args[2].ToLower() == "ok" ? HoleStatus.Ok : HoleStatus.Ng;
346→        double torque = double.Parse(args[3]);
347→        PlateData.SetResult(col, row, status, torque);
348→        return "OK:hole_result";
349→    }
350→
351→    private string CmdGetCoord(string[] args)
352→    {
353→        if (PlateData == null) return "ERR:작업판 없음";
354→        if (args.Length < 2) return "ERR:get_coord <col> <row>";
355→        int col = int.Parse(args[0]);
356→        int row = int.Parse(args[1]);
357→        // 20mm 피치 기준 좌표 (원점은 (0,0) 홀)
358→        double x = col * 20.0;
359→        double y = row * 20.0;
360→        return $"OK:{x:F1},{y:F1}";
361→    }
362→
363→    #endregion
364→
365→    #region 시나리오 연동 명령
366→
367→    /// <summary>
368→    /// TMflow → next_step: 다음 작업 스텝 반환
369→    /// 응답: OK:step_no,col,row,command,force,length,torque  또는  DONE  또는  ERR:...
370→    /// </summary>
371→    private string CmdNextStep()
372→    {
373→        if (!_scenarioRunning || _scenario == null)
374→            return "ERR:시나리오 미실행";
375→
376→        if (_currentStepIndex >= _scenario.Operations.Count)
377→        {
378→            _scenarioRunning = false;
379→            ScenarioCompleted?.Invoke();
380→            return "DONE";
381→        }
382→
383→        var op = _scenario.Operations[_currentStepIndex];
384→        StepStarted?.Invoke(_currentStepIndex, op);
385→
386→        return $"OK:{_currentStepIndex},{op.Col},{op.Row},{op.Command},{op.Force},{op.Length},{op.Torque}";
387→    }
388→
389→    /// <summary>
390→    /// TMflow → step_result col row ok|ng torque: 스텝 결과 보고
391→    /// 결과 기록 후 다음 스텝으로 전진
392→    /// </summary>
393→    private string CmdStepResult(string[] args)
394→    {
395→        if (!_scenarioRunning || _scenario == null)
396→            return "ERR:시나리오 미실행";
397→
398→        if (args.Length < 4) return "ERR:step_result <col> <row> <ok|ng> <torque>";
399→
400→        int col = int.Parse(args[0]);
401→        int row = int.Parse(args[1]);
402→        bool success = args[2].ToLower() == "ok";
403→        double torque = double.Parse(args[3]);
404→
405→        // 작업판 데이터 갱신
406→        var status = success ? HoleStatus.Ok : HoleStatus.Ng;
407→        PlateData?.SetResult(col, row, status, torque);
408→
409→        // 현재 스텝 완료 이벤트
410→        if (_currentStepIndex < _scenario.Operations.Count)
411→        {
412→            var op = _scenario.Operations[_currentStepIndex];
413→            StepCompleted?.Invoke(_currentStepIndex, op, success, torque);
414→        }
415→
416→        // 다음 스텝으로
417→        _currentStepIndex++;
418→
419→        // 전체 완료 확인
420→        if (_currentStepIndex >= _scenario.Operations.Count)
421→        {
422→            _scenarioRunning = false;
423→            ScenarioCompleted?.Invoke();
424→            return "OK:DONE";
425→        }
426→
427→        return $"OK:{_currentStepIndex}";
428→    }
429→
430→    #endregion
431→
432→    #region Busy 폴링
433→
434→    /// <summary>
435→    /// 동작 완료 대기 (busy 폴링)
436→    /// </summary>
437→    private async Task<bool> WaitUntilDone(double timeout = BUSY_TIMEOUT_SEC, bool waitStart = false)
438→    {
439→        if (waitStart)
440→        {
441→            // busy=true 시작 대기 (최대 3초)
442→            var sw = System.Diagnostics.Stopwatch.StartNew();
443→            while (sw.Elapsed.TotalSeconds < 3)
444→            {
445→                try
446→                {
447→                    if (await CbClient.GetBusyAsync()) break;
448→                }
449→                catch { }
450→                await Task.Delay(50);
451→            }
452→        }
453→
454→        // busy=false 대기
455→        var sw2 = System.Diagnostics.Stopwatch.StartNew();
456→        while (sw2.Elapsed.TotalSeconds < timeout)
457→        {
458→            try
459→            {
460→                if (!await CbClient.GetBusyAsync()) return true;
461→            }
462→            catch { }
463→            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
464→        }
465→        return false;
466→    }
467→
468→    /// <summary>
469→    /// 샹크 자동 후퇴 완료 대기
470→    /// </summary>
471→    private async Task WaitRetract()
472→    {
473→        await Task.Delay(500);
474→        var sw = System.Diagnostics.Stopwatch.StartNew();
475→        while (sw.Elapsed.TotalSeconds < 10)
476→        {
477→            try
478→            {
479→                if (!await CbClient.GetBusyAsync()) return;
480→            }
481→            catch { }
482→            await Task.Delay((int)(BUSY_POLL_SEC * 1000));
483→        }
484→    }
485→
486→    #endregion
487→}
