// ============================================================
// ScriptDecidePosition — TMflow Script Node용
// PC 브릿지 서버(TCP 5001)에 접속하여 다음 작업 위치를 수신
//
// [전제조건]
//   TMflow Variable Manager에 아래 전역변수가 선언되어 있어야 함:
//     var_bridge_ip   : string  (예: "192.168.1.100")
//     var_target_col  : int     (팔레트 열 인덱스)
//     var_target_row  : int     (팔레트 행 인덱스)
//     var_step_no     : int     (현재 스텝 번호)
//     var_command     : string  (작업 명령: tighten/loosen/pickup)
//     var_force       : int     (Z축 힘 [N])
//     var_screw_len   : float   (나사 길이 [mm])
//     var_torque      : float   (목표 토크 [Nm])
//     var_done        : bool    (true이면 시나리오 완료 → 빨간 분기)
//     var_bridge_ok   : bool    (통신 성공 여부)
//
// [브릿지 프로토콜]
//   전송: "next_step\r\n"
//   응답: "OK:step_no,col,row,command,force,length,torque\r\n"
//         또는 "DONE\r\n"
//         또는 "ERR:메시지\r\n"
// ============================================================

// --- 설정 ---
int BRIDGE_PORT = 5001
int CONNECT_TIMEOUT = 3000      // 접속 타임아웃 [ms]
int READ_TIMEOUT = 5000         // 수신 타임아웃 [ms]
int MAX_RETRY = 3               // 최대 재시도 횟수
int RETRY_DELAY = 1000          // 재시도 간격 [ms]

// --- 초기화 ---
var_done = false
var_bridge_ok = false

// --- 소켓 선언 ---
Socket bridge = var_bridge_ip, BRIDGE_PORT

// --- 재시도 루프 ---
int retry = 0
bool connected = false
string response = ""

while (retry < MAX_RETRY)
{
    // 1. 브릿지 접속
    connected = socket_open("bridge", CONNECT_TIMEOUT)
    if (connected == false)
    {
        retry++
        Display("브릿지 접속 실패", "재시도 " + GetString(retry) + "/" + GetString(MAX_RETRY))
        if (retry < MAX_RETRY)
        {
            Sleep(RETRY_DELAY)
        }
        continue
    }

    // 2. next_step 명령 전송
    bool sent = socket_sendline("bridge", "next_step")
    if (sent == false)
    {
        Display("전송 실패", "next_step")
        socket_close("bridge")
        retry++
        if (retry < MAX_RETRY)
        {
            Sleep(RETRY_DELAY)
        }
        continue
    }

    // 3. 응답 수신 (줄바꿈 종단자)
    response = socket_read_string("bridge", READ_TIMEOUT, "\n")
    socket_close("bridge")

    // 수신 실패 체크
    if (response == "" || response == empty)
    {
        Display("수신 실패", "타임아웃 또는 빈 응답")
        retry++
        if (retry < MAX_RETRY)
        {
            Sleep(RETRY_DELAY)
        }
        continue
    }

    // 수신 성공 — 루프 탈출
    var_bridge_ok = true
    break
}

// --- 재시도 모두 실패 시 ---
if (var_bridge_ok == false)
{
    Display("브릿지 통신 실패", GetString(MAX_RETRY) + "회 재시도 후 포기")
    // var_done = true로 설정하여 종료 분기로 이동
    var_done = true
}

// --- 응답 파싱 ---
if (var_bridge_ok == true)
{
    // 앞뒤 공백/CR 제거
    response = String_Trim(response)

    // DONE 체크 — 시나리오 완료
    if (response == "DONE")
    {
        var_done = true
        Display("시나리오 완료", "모든 스텝 처리됨")
    }
    // ERR 체크
    else if (String_IndexOf(response, "ERR:") == 0)
    {
        Display("브릿지 에러", response)
        var_done = true
    }
    // OK 응답 파싱: "OK:step_no,col,row,command,force,length,torque"
    else if (String_IndexOf(response, "OK:") == 0)
    {
        // "OK:" 제거 → "step_no,col,row,command,force,length,torque"
        string data = String_Substring(response, 3)

        // 쉼표로 분리
        string[] tokens = String_Split(data, ",")

        // 토큰 수 검증 (7개 필요)
        if (Length(tokens) >= 7)
        {
            var_step_no    = String_ToInteger(tokens[0])
            var_target_col = String_ToInteger(tokens[1])
            var_target_row = String_ToInteger(tokens[2])
            var_command    = String_Trim(tokens[3])
            var_force      = String_ToInteger(tokens[4])
            var_screw_len  = String_ToFloat(tokens[5])
            var_torque     = String_ToFloat(tokens[6])

            Display("다음 스텝", "Step=" + GetString(var_step_no) + " Col=" + GetString(var_target_col) + " Row=" + GetString(var_target_row) + " Cmd=" + var_command)
        }
        else
        {
            Display("파싱 에러", "토큰 부족: " + data)
            var_done = true
        }
    }
    else
    {
        // 예상치 못한 응답
        Display("알 수 없는 응답", response)
        var_done = true
    }
}

// ============================================================
// ScriptReportResult — TMflow Script Node용 (Tightening 서브플로우 이후)
// 체결 결과를 PC 브릿지 서버(TCP 5001)에 보고
//
// [전제조건]
//   TMflow Variable Manager에 아래 전역변수가 선언되어 있어야 함:
//     var_bridge_ip    : string  (PC 브릿지 IP)
//     var_target_col   : int     (현재 작업 열)
//     var_target_row   : int     (현재 작업 행)
//     var_tighten_ok   : bool    (체결 성공 여부, Tightening 서브플로우에서 설정)
//     var_achieved_torque : float (달성 토크 [Nm], GetParameters에서 읽은 값)
//     var_report_ok    : bool    (결과 보고 성공 여부)
//     var_scenario_done : bool   (시나리오 전체 완료 여부)
//
// [브릿지 프로토콜]
//   전송: "step_result col row ok|ng torque\r\n"
//   응답: "OK:N\r\n"    (N=다음스텝번호)
//         또는 "OK:DONE\r\n"  (시나리오 완료)
//         또는 "ERR:메시지\r\n"
// ============================================================

// --- 설정 ---
int BRIDGE_PORT = 5001
int CONNECT_TIMEOUT = 3000
int READ_TIMEOUT = 5000
int MAX_RETRY = 3
int RETRY_DELAY = 1000

// --- 초기화 ---
var_report_ok = false
var_scenario_done = false

// --- 결과 문자열 생성 ---
string result_str = "ng"
if (var_tighten_ok == true)
{
    result_str = "ok"
}

// 토크 값을 소수점 2자리 문자열로 변환
string torque_str = GetString(var_achieved_torque, 2)

// 전송할 명령: "step_result col row ok|ng torque"
string cmd = "step_result " + GetString(var_target_col) + " " + GetString(var_target_row) + " " + result_str + " " + torque_str

// --- 소켓 선언 ---
Socket bridge = var_bridge_ip, BRIDGE_PORT

// --- 재시도 루프 ---
int retry = 0
bool connected = false
string response = ""

while (retry < MAX_RETRY)
{
    // 1. 브릿지 접속
    connected = socket_open("bridge", CONNECT_TIMEOUT)
    if (connected == false)
    {
        retry++
        Display("결과보고 접속 실패", "재시도 " + GetString(retry) + "/" + GetString(MAX_RETRY))
        if (retry < MAX_RETRY)
        {
            Sleep(RETRY_DELAY)
        }
        continue
    }

    // 2. step_result 명령 전송
    bool sent = socket_sendline("bridge", cmd)
    if (sent == false)
    {
        Display("결과보고 전송 실패", cmd)
        socket_close("bridge")
        retry++
        if (retry < MAX_RETRY)
        {
            Sleep(RETRY_DELAY)
        }
        continue
    }

    // 3. 응답 수신
    response = socket_read_string("bridge", READ_TIMEOUT, "\n")
    socket_close("bridge")

    if (response == "" || response == empty)
    {
        Display("결과보고 수신 실패", "타임아웃")
        retry++
        if (retry < MAX_RETRY)
        {
            Sleep(RETRY_DELAY)
        }
        continue
    }

    // 수신 성공
    var_report_ok = true
    break
}

// --- 응답 파싱 ---
if (var_report_ok == true)
{
    response = String_Trim(response)

    if (String_IndexOf(response, "OK:DONE") == 0)
    {
        // 시나리오 전체 완료
        var_scenario_done = true
        Display("시나리오 완료", "모든 스텝 처리 완료")
    }
    else if (String_IndexOf(response, "OK:") == 0)
    {
        // 정상 — 다음 스텝 번호 반환 (사용하지 않지만 로그 표시)
        string next_step = String_Substring(response, 3)
        Display("결과보고 완료", "다음 스텝=" + next_step + " 토크=" + torque_str + "Nm")
    }
    else if (String_IndexOf(response, "ERR:") == 0)
    {
        Display("결과보고 에러", response)
    }
    else
    {
        Display("알 수 없는 응답", response)
    }
}
else
{
    Display("결과보고 실패", GetString(MAX_RETRY) + "회 재시도 후 포기")
}
